import"./modulepreload-polyfill-B5Qt9EMX.js";document.addEventListener("DOMContentLoaded",()=>{const s=document.getElementById("loginForm"),e=document.getElementById("errorMsg");s.addEventListener("submit",async a=>{var n;a.preventDefault(),e.classList.add("hidden");const r=document.getElementById("email").value.trim(),d=document.getElementById("password").value;try{const o=await fetch("/api/auth/login",{method:"POST",headers:{"Content-Type":"application/json",Accept:"application/json"},body:JSON.stringify({email:r,password:d})}),t=await o.json();if(console.log("Response:",t),!o.ok){e.textContent=t.message||"Email atau password salah",e.classList.remove("hidden");return}t.token&&localStorage.setItem("token",t.token);const i=((n=t.user)==null?void 0:n.role)==="admin"?"/admin":"/home";document.body.classList.remove("page-ready"),setTimeout(()=>{window.location.href=i},180)}catch(o){console.error(o),e.textContent="Tidak dapat terhubung ke server",e.classList.remove("hidden")}})});
